class Solution:
    def palindromePartition(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[0] * n for _ in range(n)]
        for i in range(n - 1, -1, -1):
            for j in range(i, n):
                if s[i] == s[j]:
                    if i + 1 > j - 1:
                        dp[i][j] = dp[i + 1][j - 1]
                    else:
                        dp[i][j] = 0
                else:
                    dp[i][j] = 1 + min(dp[i + 1][j], dp[i][j - 1])
        res = dp[0][n - 1]
        i, cnt = 0, 0
        while i < n:
            j = i
            while j < n and dp[i][j] == dp[i][j - 1]:
                j += 1
            res -= dp[i][j - 1]
            cnt += 1
            i = j
        return res - max(0, cnt - k)
